-- Create "purchase_orders" table
CREATE TABLE "purchase_orders" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "purchase_order_no" character varying NOT NULL,
  "supplier_purchase_order_no" character varying NULL,
  "supplier_snapshot" jsonb NULL,
  "purchase_date" timestamptz NOT NULL,
  "expected_arrival_date" timestamptz NULL,
  "lifecycle_status" character varying NOT NULL DEFAULT 'draft',
  "note" character varying NULL,
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  "supplier_id" bigint NOT NULL,
  PRIMARY KEY ("id"),
  CONSTRAINT "purchase_orders_suppliers_purchase_orders" FOREIGN KEY ("supplier_id") REFERENCES "suppliers" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION,
  CONSTRAINT "purchase_orders_lifecycle_status_allowed" CHECK ((lifecycle_status)::text = ANY ((ARRAY['draft'::character varying, 'submitted'::character varying, 'approved'::character varying, 'closed'::character varying, 'canceled'::character varying])::text[]))
);
-- Create index "purchaseorder_expected_arrival_date" to table: "purchase_orders"
CREATE INDEX "purchaseorder_expected_arrival_date" ON "purchase_orders" ("expected_arrival_date");
-- Create index "purchaseorder_lifecycle_status" to table: "purchase_orders"
CREATE INDEX "purchaseorder_lifecycle_status" ON "purchase_orders" ("lifecycle_status");
-- Create index "purchaseorder_purchase_date" to table: "purchase_orders"
CREATE INDEX "purchaseorder_purchase_date" ON "purchase_orders" ("purchase_date");
-- Create index "purchaseorder_purchase_order_no" to table: "purchase_orders"
CREATE UNIQUE INDEX "purchaseorder_purchase_order_no" ON "purchase_orders" ("purchase_order_no");
-- Create index "purchaseorder_supplier_id" to table: "purchase_orders"
CREATE INDEX "purchaseorder_supplier_id" ON "purchase_orders" ("supplier_id");
-- Create index "purchaseorder_supplier_purchase_order_no" to table: "purchase_orders"
CREATE INDEX "purchaseorder_supplier_purchase_order_no" ON "purchase_orders" ("supplier_purchase_order_no");
-- Create "purchase_order_items" table
CREATE TABLE "purchase_order_items" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "line_no" bigint NOT NULL,
  "material_code_snapshot" character varying NULL,
  "material_name_snapshot" character varying NULL,
  "color_snapshot" character varying NULL,
  "purchased_quantity" numeric(20,6) NOT NULL,
  "unit_price" numeric(20,6) NULL,
  "amount" numeric(20,6) NULL,
  "expected_arrival_date" timestamptz NULL,
  "line_status" character varying NOT NULL DEFAULT 'open',
  "note" character varying NULL,
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  "material_id" bigint NOT NULL,
  "purchase_order_id" bigint NOT NULL,
  "unit_id" bigint NOT NULL,
  PRIMARY KEY ("id"),
  CONSTRAINT "purchase_order_items_materials_purchase_order_items" FOREIGN KEY ("material_id") REFERENCES "materials" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION,
  CONSTRAINT "purchase_order_items_purchase_orders_items" FOREIGN KEY ("purchase_order_id") REFERENCES "purchase_orders" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION,
  CONSTRAINT "purchase_order_items_units_purchase_order_items" FOREIGN KEY ("unit_id") REFERENCES "units" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION,
  CONSTRAINT "purchase_order_items_amount_non_negative" CHECK ((amount IS NULL) OR (amount >= (0)::numeric)),
  CONSTRAINT "purchase_order_items_line_no_positive" CHECK (line_no > 0),
  CONSTRAINT "purchase_order_items_line_status_allowed" CHECK ((line_status)::text = ANY ((ARRAY['open'::character varying, 'closed'::character varying, 'canceled'::character varying])::text[])),
  CONSTRAINT "purchase_order_items_purchased_qty_positive" CHECK (purchased_quantity > (0)::numeric),
  CONSTRAINT "purchase_order_items_unit_price_non_negative" CHECK ((unit_price IS NULL) OR (unit_price >= (0)::numeric))
);
-- Create index "purchaseorderitem_expected_arrival_date" to table: "purchase_order_items"
CREATE INDEX "purchaseorderitem_expected_arrival_date" ON "purchase_order_items" ("expected_arrival_date");
-- Create index "purchaseorderitem_line_status" to table: "purchase_order_items"
CREATE INDEX "purchaseorderitem_line_status" ON "purchase_order_items" ("line_status");
-- Create index "purchaseorderitem_material_id" to table: "purchase_order_items"
CREATE INDEX "purchaseorderitem_material_id" ON "purchase_order_items" ("material_id");
-- Create index "purchaseorderitem_purchase_order_id_line_no" to table: "purchase_order_items"
CREATE UNIQUE INDEX "purchaseorderitem_purchase_order_id_line_no" ON "purchase_order_items" ("purchase_order_id", "line_no");
-- Create index "purchaseorderitem_unit_id" to table: "purchase_order_items"
CREATE INDEX "purchaseorderitem_unit_id" ON "purchase_order_items" ("unit_id");
-- Modify "purchase_receipt_items" table
ALTER TABLE "purchase_receipt_items" ADD COLUMN "purchase_order_item_id" bigint NULL, ADD CONSTRAINT "purchase_receipt_items_purchase_order_items_purchase_receipt_it" FOREIGN KEY ("purchase_order_item_id") REFERENCES "purchase_order_items" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION;
-- Create index "purchasereceiptitem_purchase_order_item_id" to table: "purchase_receipt_items"
CREATE INDEX "purchasereceiptitem_purchase_order_item_id" ON "purchase_receipt_items" ("purchase_order_item_id");
